import{c as t,Q as a,j as r,m as o}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Prepare a set","description":"","frontmatter":{},"headers":[],"relativePath":"workflows/prepare-a-set.md","filePath":"workflows/prepare-a-set.md","lastUpdated":null}'),s={name:"workflows/prepare-a-set.md"};function i(d,e,n,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="prepare-a-set" tabindex="-1">Prepare a set <a class="header-anchor" href="#prepare-a-set" aria-label="Permalink to &quot;Prepare a set&quot;">​</a></h1><p>Audience: DJs using the browser UI<br> Goal: turn a few tracks into a reviewed export<br> Type: tutorial</p><p>This workflow starts with tracks you trust, creates candidates, builds a preview, and exports only after you review the result.</p><h2 id="before-you-start" tabindex="-1">Before you start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before you start&quot;">​</a></h2><p>You need a scanned library and enough analysis for the search mode you plan to use:</p><ul><li>SONARA features for explainable feature search;</li><li>MERT embeddings for audio seed similarity;</li><li>CLAP embeddings for text prompts;</li><li>SONARA, MERT, MAEST, and CLAP for Smart Set Builder.</li></ul><h2 id="_1-pick-the-first-anchors" tabindex="-1">1. Pick the first anchors <a class="header-anchor" href="#_1-pick-the-first-anchors" aria-label="Permalink to &quot;1. Pick the first anchors&quot;">​</a></h2><p>In the library table, find one to five tracks that represent the sound you want. Avoid picking several tracks by the same known artist if you plan to use Smart Set Builder, because the SET route keeps a strict artist guard.</p><h2 id="_2-search-around-the-anchors" tabindex="-1">2. Search around the anchors <a class="header-anchor" href="#_2-search-around-the-anchors" aria-label="Permalink to &quot;2. Search around the anchors&quot;">​</a></h2><p>Use the search tab that matches the job:</p><table tabindex="0"><thead><tr><th>Need</th><th>Tab</th></tr></thead><tbody><tr><td>similar audio feel from selected tracks</td><td><code>MERT</code></td></tr><tr><td>explainable musical features</td><td><code>SONARA</code></td></tr><tr><td>text prompt such as &quot;dark rolling techno&quot;</td><td><code>CLAP</code></td></tr><tr><td>ordered set preview</td><td><code>SET</code></td></tr><tr><td>promoted personal concept</td><td><code>CLASS</code></td></tr></tbody></table><p>Add only tracks you want to audition. Search results are candidates, not a finished set.</p><h2 id="_3-generate-a-set-preview" tabindex="-1">3. Generate a SET preview <a class="header-anchor" href="#_3-generate-a-set-preview" aria-label="Permalink to &quot;3. Generate a SET preview&quot;">​</a></h2><p>Open <code>SET</code>, choose <code>Manual</code> or <code>Auto</code>, set the track limit, energy curve, diversity, and BPM mode, then generate a preview.</p><p>The preview is read-only. It becomes part of the current set only when you use the explicit add action.</p><h2 id="_4-listen-and-remove-weak-links" tabindex="-1">4. Listen and remove weak links <a class="header-anchor" href="#_4-listen-and-remove-weak-links" aria-label="Permalink to &quot;4. Listen and remove weak links&quot;">​</a></h2><p>Use preview playback, metadata, BPM/key, and your own judgement. Similarity scores are ranking hints; they do not know the room, crowd, or transition style.</p><h2 id="_5-export" tabindex="-1">5. Export <a class="header-anchor" href="#_5-export" aria-label="Permalink to &quot;5. Export&quot;">​</a></h2><p>When the current set looks useful, export it as a playlist/report from the UI. Export writes playlist/report files. It does not rewrite source audio.</p>',19)])])}const f=t(s,[["render",i]]);export{u as __pageData,f as default};
